def setup_logging():
    """Initialize the logging configuration for the application."""
    logging.config.dictConfig(LOGGING_CONFIG)
    logger = logging.getLogger("app")
    logger.info("Logging infrastructure initialized successfully.")
    return logger


class AppLoggerAdapter(logging.LoggerAdapter):
    """Custom logger adapter that injects extra context into log records."""

    def __init__(self, logger, extra=None):
        super().__init__(logger, extra or {})

    def process(self, msg, kwargs):
        extra = kwargs.get("extra", {})
        extra.update(self.extra)

        context_parts = []
        if "request_id" in extra:
            context_parts.append(f"req_id={extra['request_id']}")
        if "user_id" in extra:
            context_parts.append(f"user={extra['user_id']}")
        if "ip_address" in extra:
            context_parts.append(f"ip={extra['ip_address']}")

        context_str = " ".join(context_parts)
        if context_str:
            msg = f"[{context_str}] {msg}"

        kwargs["extra"] = extra
        return msg, kwargs


def get_logger(name, **extra_context):
    """
    Get a logger with optional context.
    
    Args:
        name: Logger name (e.g., 'app', 'app.access', 'app.security')
        **extra_context: Additional context fields (request_id, user_id, etc.)
    
    Returns:
        AppLoggerAdapter with the given context
    """
    logger = logging.getLogger(name)
    return AppLoggerAdapter(logger, extra=extra_context)


